var e=JSON.parse(`[{"id":"L4_1","type":"dialog","speaker":"SIGMA_RAS_NULL_NULL","text":{"KOREA":"와! 여긴 사람도 물고기도 정말 많아!","JPN":"わあ！　ここって人もお魚もすごくたくさん！","ENG":"Wow! There are so many people and fish here!","TWN":"哇！這裡有好多人跟好多魚喔！"},"stage":{"bg":"AQUARIUM","slots":{"L":null,"C":{"char_id":"SIGMA_RAS_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"GSWORD_ADMIN_SPORTS_NULL","text":{"KOREA":"후훗. 시그마는 모처럼 온 소풍이라 신났나 보네.","JPN":"ふふっ、シグマちゃんは久しぶりの遠足にすごく舞い上がっているみたいね。","ENG":"Haha. Sigma seems excited about her outing today.","TWN":"呵呵，西格瑪難得可以出來放風，很開心吧？"},"stage":{"bg":"AQUARIUM","slots":{"L":null,"C":{"char_id":"GSWORD_ADMIN_SPORTS_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"GSWORD_ADMIN_SPORTS_NULL","text":{"KOREA":"릴리도 수족관에 처음 놀러와 본다고 했지?","JPN":"リリーも水族館は初めてなんでしょ？","ENG":"It's your first time to the aquarium too, Lily?","TWN":"莉莉也是第一次來水族館玩吧？"},"stage":{"bg":"AQUARIUM","slots":{"L":null,"C":{"char_id":"GSWORD_ADMIN_SPORTS_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"MASK_MAID_NULL_NULL","text":{"KOREA":"죄송하지만, 전 놀러 온 게 아닙니다.","JPN":"申し訳ありませんが、私は遊びにきたわけではありません。","ENG":"I am sorry, but I am not here for pleasure.","TWN":"抱歉，我不是來玩的。"},"stage":{"bg":"AQUARIUM","slots":{"L":null,"C":{"char_id":"MASK_MAID_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"MASK_MAID_NULL_NULL","text":{"KOREA":"견문을 넓히고 오라는 주인님의 지시에 따라서 왔을 뿐이죠.","JPN":"見聞を広げてこいというご主人様の指示に従い、来たまでです。","ENG":"I am here because Master has ordered that I broaden my horizons.","TWN":"是主人要我出來增廣見聞，我才奉主人之命來的。"},"stage":{"bg":"AQUARIUM","slots":{"L":null,"C":{"char_id":"MASK_MAID_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"GSWORD_ADMIN_SPORTS_NULL","text":{"KOREA":"그래? 어떻게 하라고 했는데?","JPN":"そう？　何をしろって言ってた？","ENG":"Oh, yeah? Now what did he say, exactly?","TWN":"是嗎？他是怎麼說的？"},"stage":{"bg":"AQUARIUM","slots":{"L":null,"C":{"char_id":"GSWORD_ADMIN_SPORTS_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"MASK_MAID_NULL_NULL","text":{"KOREA":"다양한 해양생물을 확인하고 스쿠버 다이버들의 공연도 관람하라고 하셨습니다.","JPN":"様々な海洋生物を確認し、スクーバダイバーたちの公演も鑑賞してこいと言われました。","ENG":"He told me to observe the various marine lifeforms and watch the scuba-diving performance.","TWN":"主人說要確認各樣海洋生物，還要欣賞潛水秀。"},"stage":{"bg":"AQUARIUM","slots":{"L":null,"C":{"char_id":"MASK_MAID_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"MASK_MAID_NULL_NULL","text":{"KOREA":"덧붙여서 방문을 인증할 수 있는 기념품도 꼭 챙겨 오라고 하셨죠.","JPN":"加えて、訪問を証明できる記念品もしっかり持って帰ってくるようにとおっしゃっていました。","ENG":"Also, to bring a souvenir as evidence of my visit.","TWN":"另外還要買紀念品，證明有來過。"},"stage":{"bg":"AQUARIUM","slots":{"L":null,"C":{"char_id":"MASK_MAID_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"GSWORD_ADMIN_SPORTS_NULL","text":{"KOREA":"그게 잘 놀고 오라는 뜻이야.","JPN":"それって楽しく遊んできなさいという意味なのよ。","ENG":"That means go have fun.","TWN":"這就是要你好好玩的意思。"},"stage":{"bg":"AQUARIUM","slots":{"L":null,"C":{"char_id":"GSWORD_ADMIN_SPORTS_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"MASK_MAID_NULL_NULL","text":{"KOREA":"……저에게는 따님을 보필해야 할 의무가 있어요.","JPN":"……私にはお嬢様を見守る義務があります。","ENG":"...But I have a duty to care for Sigma.","TWN":"……我有義務要保護好小姐。"},"stage":{"bg":"AQUARIUM","slots":{"L":null,"C":{"char_id":"MASK_MAID_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"MASK_MAID_NULL_NULL","text":{"KOREA":"이런 구경거리에 혹해서야 주인님의 메이드로서 실격이에요.","JPN":"こんな見せ物に魅了されているようでは、ご主人様のメイドとして失格です。","ENG":"If I am tempted by these kinds of spectacles, I will be unqualified to be Master's maid.","TWN":"要是因為玩樂而不務正業，那我就是個失職的女僕。"},"stage":{"bg":"AQUARIUM","slots":{"L":null,"C":{"char_id":"MASK_MAID_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"SIGMA_RAS_NULL_NULL","text":{"KOREA":"릴리! 빨리 와서 이것 좀 봐!","JPN":"リリー！　早くこっちに来て、これを見てみてよ！","ENG":"Lily! Come here quick and look at this!","TWN":"莉莉快來！你看這個！"},"stage":{"bg":"AQUARIUM","slots":{"L":null,"C":{"char_id":"SIGMA_RAS_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"MASK_MAID_NULL_NULL","text":{"KOREA":"네, 따님. 금방 가겠습니다.","JPN":"はい、お嬢様。すぐに。","ENG":"Yes, Sigma. I will be right there.","TWN":"是，小姐，我馬上過去。"},"stage":{"bg":"AQUARIUM","slots":{"L":null,"C":{"char_id":"MASK_MAID_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"MASK_MAID_NULL_NULL","text":{"KOREA":"먼저 실례하죠. 알렉스 님도 저에게 어쩔티비 저쩔티비 하지 마시고 구경하시면 됩니다.","JPN":"お先に失礼します。アレックス様も私にウザッたくなさらずに鑑賞を楽しめばいいのです。","ENG":"Excuse me. You should stop telling me about FOMO and come watch with us, Alex.","TWN":"失禮了。請雅蕾克絲小姐也不要再跟我五四三，你就玩你的吧。"},"stage":{"bg":"AQUARIUM","slots":{"L":null,"C":{"char_id":"MASK_MAID_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"GSWORD_ADMIN_SPORTS_NULL","text":{"KOREA":"흐음…… 요즘 아이들 말투는 알아듣기가 참 어렵네.","JPN":"はぁ……最近の子の話し方ってわかりづらいわね。","ENG":"Hmm... It's hard to understand what kids are saying these days.","TWN":"嗯……最近的孩子講話真難懂。"},"stage":{"bg":"AQUARIUM","slots":{"L":null,"C":{"char_id":"GSWORD_ADMIN_SPORTS_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"SIGMA_RAS_NULL_NULL","text":{"KOREA":"쟤는 <color=#ffd34c>피라냐</color>, 저기 저 큰 건 <color=#ffd34c>피라루쿠</color>야. 모두 아마존에서 발견할 수 있지.","JPN":"あれは<color=#ffd34c>ピラニア</color>、あそこの大きいのは<color=#ffd34c>ピラルクー</color>だよ。どっちもアマゾンで見られるの。","ENG":"That one's a <color=#ffd34c>piranha</color>, and that big one is called a <color=#ffd34c>pirarucu</color>. They can all be found in the Amazon.","TWN":"牠是<color=#ffd34c>食人魚</color>，, 很大的那條是<color=#ffd34c>象魚</color>，牠們都是在亞馬遜河中發現的喔。"},"stage":{"bg":"AQUARIUM","slots":{"L":{"char_id":"SIGMA_RAS_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L24_1","type":"dialog","speaker":"SIGMA_RAS_NULL_NULL","text":{"KOREA":"앗! 나 쟤도 누군지 알아!","JPN":"あっ！　あれも知っているお魚！","ENG":"Oh! I know what that one is too!","TWN":"喔！牠我好像也知道！"},"stage":{"bg":"AQUARIUM","slots":{"L":null,"C":null,"R":{"char_id":"SIGMA_RAS_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L25_1","type":"dialog","speaker":"SIGMA_RAS_NULL_NULL","text":{"KOREA":"이름은 <color=#ffd34c>흑가오리</color>고 <color=#ffd34c>매가오리목 색가오리과</color>의 가오리야!","JPN":"名前は<color=#ffd34c>ホシエイ</color>で、<color=#ffd34c>トビエイ目アカエイ科</color>に属するエイなんだ！","ENG":"It's called a <color=#ffd34c>pitted stingray</color> and it's part of the <color=#ffd34c>Dasyatidae family</color>!","TWN":"牠叫<color=#ffd34c>松原魟</color>，屬於<color=#ffd34c>鱝目，魟科</color>！"},"stage":{"bg":"AQUARIUM","slots":{"L":null,"C":null,"R":{"char_id":"SIGMA_RAS_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L26_1","type":"dialog","speaker":"SIGMA_RAS_NULL_NULL","text":{"KOREA":"길이가 2미터나 돼서 사람을 한 번에 덮을 수 있어. 이불처럼 말이야.","JPN":"長さが2メートルもあって、人を覆えるほどなんだよ。お布団みたいにね。","ENG":"Its disc is 2 meters wide and can even cover people. Like a blanket.","TWN":"長約2公尺，可以把整個人都蓋住，像棉被一樣。"},"stage":{"bg":"AQUARIUM","slots":{"L":null,"C":null,"R":{"char_id":"SIGMA_RAS_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L28_1","type":"dialog","speaker":"MASK_MAID_NULL_NULL","text":{"KOREA":"2미터……. 이불처럼 덮을 수도 있다…….","JPN":"2メートル……布団のように覆えるっと……","ENG":"2 meters... Can be used as a cover like a blanket...","TWN":"2公尺……像棉被一樣……"},"stage":{"bg":"AQUARIUM","slots":{"L":null,"C":{"char_id":"MASK_MAID_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};